import { HostCategory } from '@/types';

export const fetchCategories = async (
  setLoading: (loading: boolean) => void,
  currentPage?: Number,
  categoriesPerPage?: Number,
  paginate?: boolean,
  toast?: any
): Promise<HostCategory[]> => {
  const urlWithPagentaion = `http://localhost:8080/host-categories?page=${currentPage}&perPage=${categoriesPerPage}`;
  const url = `http://localhost:8080/host-categories`;
  try {
    setLoading(true);
    const res = await fetch(`${paginate ? urlWithPagentaion : url}`, {
      method: 'GET',
      headers: {
        'Content-Type': 'application/json',
      },
    });

    if (!res.ok) {
      throw new Error(`Failed to fetch event: ${res.statusText}`);
    }

    const data = await res.json();
    console.log('host categoris', data);
    return data.categories || [];
  } catch (error: unknown) {
    if (error instanceof Error) {
      toast({
        title: 'Error',
        description: error.message,
        variant: 'destructive',
      });
    } else {
      toast({
        title: 'Error',
        description: 'An unexpected error occurred.',
        variant: 'destructive',
      });
    }
    return [];
  } finally {
    setLoading(false);
  }
};
